sql:
SELECT title, developer, publisher
FROM games
WHERE release_year > 2000;

SELECT title
FROM games
WHERE console_id = 0 AND release_year > 1990;

SELECT save_data, upload_date, game_version
FROM game_saves
WHERE save_id = 1;

SELECT console_name, console_model 
FROM consoles 
WHERE console_id = 1;

SELECT region, COUNT(*) as total_games
FROM game_releases
GROUP BY region;
